const GSHEET_BASE = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vQnBn6u5fFx9rBg6fkRHO7xC7GPztVRRMO3JNwogo1KUT8Mn76yYzoq6YJtjs4nlqPkkIJAwKtwo_qr/pub?output=csv';
const GSHEET_IEP_URL = GSHEET_BASE + '&gid=1311916965';
const GSHEET_SL_URL  = GSHEET_BASE + '&gid=0';
const BRAND_MAP_REV = {'MiraLAX':'Miralax','Shopper':'Shoppers'};

function parseCSV(text){
  const lines=text.split('\n');
  if(lines.length<2)return[];
  const hdr=lines[0].match(/(".*?"|[^,]+)/g).map(h=>h.replace(/^"|"$/g,'').trim());
  return lines.slice(1).filter(l=>l.trim()).map(line=>{
    const vals=[];let cur='',inQ=false;
    for(let i=0;i<line.length;i++){
      if(line[i]==='"'){inQ=!inQ;}
      else if(line[i]===','&&!inQ){vals.push(cur.replace(/^"|"$/g,'').trim());cur='';}
      else{cur+=line[i];}
    }
    vals.push(cur.replace(/^"|"$/g,'').trim());
    const obj={};hdr.forEach((h,i)=>obj[h]=vals[i]||'');return obj;
  });
}

async function fetchCSV(url){
  // Tenta fetch direto (funciona quando hospedado em servidor web)
  try{
    const res=await fetch(url);
    if(res.ok)return await res.text();
  }catch(e){}
  // Fallback: CORS proxy (funciona localmente via file://)
  try{
    const proxy='https://api.allorigins.win/raw?url='+encodeURIComponent(url);
    const res=await fetch(proxy);
    if(res.ok)return await res.text();
  }catch(e){}
  return null;
}

function applyIEPSync(rows){
  const newLJ={};
  const cancelledKeys=new Set();
  rows.forEach(r=>{
    const brand=BRAND_MAP_REV[r['Brand']]||r['Brand'];
    const exp=r['Experiment'];
    if(!brand||!exp)return;
    const key=brand+'|'+exp;
    const st=(r['Status']||'').toLowerCase();
    const l1=r['Link 1']||'';
    const l2=r['Link 2']||'';
    if(st==='cancelled'||(!l1&&!l2)){cancelledKeys.add(key);return;}
    const ljs=[];
    const name=r['Project Name']||'';
    if(l1)ljs.push({file:exp+' - '+name+'.pptx',url:l1});
    if(l2)ljs.push({file:exp+' - '+name+' (2).pptx',url:l2});
    if(ljs.length)newLJ[key]=ljs;
  });
  Object.keys(newLJ).forEach(k=>learningJourneyMap[k]=newLJ[k]);
  Object.keys(learningJourneyMap).forEach(k=>{if(cancelledKeys.has(k))delete learningJourneyMap[k];});
  iepProjects.forEach(p=>{
    const k=p.brand+'|'+p.experiment_id;
    if(cancelledKeys.has(k)&&p.rounds>0)p.rounds=0;
    if(newLJ[k]&&p.rounds===0)p.rounds=1;
  });
}

function applySLSync(rows){
  rows.forEach(r=>{
    const link=r['Link']||'';
    const title=r['Report Title']||'';
    const brand=r['Brand']||'';
    if(!link||!title)return;
    const match=projects.find(p=>p.theme===title&&p.brand===brand);
    if(match)match.link=link;
  });
}

async function syncFromGSheet(){
  try{
    const [iepCSV, slCSV] = await Promise.all([fetchCSV(GSHEET_IEP_URL), fetchCSV(GSHEET_SL_URL)]);
    let synced=false;
    if(iepCSV){applyIEPSync(parseCSV(iepCSV));synced=true;}
    if(slCSV){applySLSync(parseCSV(slCSV));synced=true;}
    if(synced){initHome();initSL();initIEP();console.log('Hub synced from Google Sheets');}
    else{console.log('Hub using embedded data (offline mode)');}
  }catch(e){console.log('Hub using embedded data (offline mode)');}
}

