// ===== FLOATING TOOLTIP =====
let ftip=null;
function initTooltip(){
  ftip=document.createElement('div');ftip.className='float-tooltip';document.body.appendChild(ftip);
  document.addEventListener('mousemove',e=>{if(ftip.classList.contains('show')){ftip.style.left=(e.clientX+14)+'px';ftip.style.top=(e.clientY-10)+'px';}});
}
function showTip(html){ftip.innerHTML=html;ftip.classList.add('show');}
function hideTip(){ftip.classList.remove('show');}

// ===== SCROLL REVEAL =====
function initReveal(){
  const obs=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');obs.unobserve(e.target);}});},{threshold:0.1,rootMargin:'0px 0px -40px 0px'});
  document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));
}

function switchPage(p){
  document.querySelectorAll('.page-view').forEach(v=>v.classList.remove('active'));
  document.getElementById('page-'+p).classList.add('active');
  document.querySelectorAll('.nav-btn').forEach(b=>b.classList.toggle('active',b.dataset.page===p));
  window.scrollTo(0,0);
  setTimeout(initReveal,100);
}

function classifyTools(t){
  if(!t)return[];const s=t.toLowerCase();const r=[];
  if(s.includes('mention')||s.includes('social')||s.includes('conversation')||s.includes('buzz'))r.push('Mentions');
  if(s.includes('search')||s.includes('google')||s.includes('keyword')||s.includes('seo'))r.push('Search Behavior');
  if(s.includes('review')||s.includes('amazon')||s.includes('rating')||s.includes('walmart'))r.push('Reviews');
  if(r.length===0){if(s.includes('benchmark')||s.includes('landscape'))r.push('Search Behavior');else r.push('Mentions');}
  return r;
}

// ===== ANIMATED COUNTER =====
function animateCounter(el, target, duration=1200){
  let start=0;const step=target/((duration/16));
  const timer=setInterval(()=>{
    start+=step;
    if(start>=target){el.textContent=target;clearInterval(timer);}
    else el.textContent=Math.floor(start);
  },16);
}

// ===== SPARKLINE MINI CHART =====
function drawSparkline(cat, color){
  const years=[2021,2022,2023,2024,2025,2026];
  const vals=years.map(y=>projects.filter(p=>p.category===cat&&p.year==y&&p.link&&p.link.startsWith('http')).length);
  const max=Math.max(...vals,1);
  return `<div class="sparkline-container">${vals.map((v,i)=>{
    const h=Math.max(3, (v/max)*28);
    return `<div class="spark-bar" style="height:${h}px;width:8px;background:${color};opacity:${v>0?0.5+v/max*0.5:0.15}"
      onmouseover="showTip('<b>${years[i]}</b>: ${v} project${v!==1?'s':''}')" onmouseout="hideTip()"></div>`;
  }).join('')}</div>`;
}

// ===== SVG DONUT CHART (ENHANCED) =====
function drawDonut(containerId, data, size=200){
  const total=data.reduce((s,d)=>s+d.value,0);
  let cumulative=0;
  const gap=0.015;
  const paths=data.map((d,idx)=>{
    const startAngle=cumulative*2*Math.PI-Math.PI/2;
    cumulative+=d.value/total;
    const endAngle=cumulative*2*Math.PI-Math.PI/2-gap;
    const r=size/2-12;const cx=size/2;const cy=size/2;
    const x1=cx+r*Math.cos(startAngle);const y1=cy+r*Math.sin(startAngle);
    const x2=cx+r*Math.cos(endAngle);const y2=cy+r*Math.sin(endAngle);
    const large=d.value/total>0.5?1:0;
    return `<path d="M${x1},${y1} A${r},${r} 0 ${large} 1 ${x2},${y2}"
      stroke="${d.color}" stroke-width="26" fill="none" stroke-linecap="round"
      style="cursor:pointer;transition:all 0.3s;opacity:0;animation:donutIn 0.6s ease forwards ${0.1+idx*0.12}s;filter:drop-shadow(0 0 3px ${d.color}40)"
      onmouseover="this.style.strokeWidth='34';this.style.filter='drop-shadow(0 0 8px ${d.color}80)';document.getElementById('donut-label').innerHTML='<div style=color:${d.color};font-weight:800;font-size:24px>${d.value}</div><div style=font-size:10px;color:#7a8ea0;text-transform:uppercase;letter-spacing:1px>${d.label}</div>';showTip('<span style=color:${d.color};font-weight:700>${d.label}</span><br>${d.value} projects &bull; ${(d.value/total*100).toFixed(0)}%')"
      onmouseout="this.style.strokeWidth='26';this.style.filter='drop-shadow(0 0 3px ${d.color}40)';document.getElementById('donut-label').innerHTML='<div style=color:var(--accent-cyan);font-weight:800;font-size:24px>${total}</div><div style=font-size:10px;color:#7a8ea0;text-transform:uppercase;letter-spacing:1px>Total</div>';hideTip()"
      onclick="switchHome('${d.label}')"/>`;
  }).join('');
  return `<svg viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">
    <style>@keyframes donutIn{from{opacity:0;stroke-dashoffset:300}to{opacity:1;stroke-dashoffset:0}}</style>
    <!-- subtle bg ring -->
    <circle cx="${size/2}" cy="${size/2}" r="${size/2-12}" fill="none" stroke="rgba(255,255,255,0.03)" stroke-width="26"/>
    ${paths}
    <foreignObject x="${size/2-55}" y="${size/2-28}" width="110" height="56">
      <div id="donut-label" style="text-align:center;display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%">
        <div style="color:var(--accent-cyan);font-weight:800;font-size:24px">${total}</div>
        <div style="font-size:10px;color:#7a8ea0;text-transform:uppercase;letter-spacing:1px">Total</div>
      </div>
    </foreignObject>
  </svg>`;
}

