function populateStats(){
  const slL=projects.filter(p=>p.link&&p.link.startsWith('http')).length;
  const tot=slL+iepProjects.length;
  const stats=[
    {num:5,lbl:'Years of Tracking'},
    {num:tot,lbl:'Total Projects'},
    {num:slL,lbl:'SL Reports'},
    {num:iepProjects.reduce((s,p)=>s+p.rounds,0),lbl:'IEP Rounds'}
  ];
  document.getElementById('statsRow').innerHTML=stats.map((s,i)=>`<div class="stat-pill" style="animation:scaleIn 0.5s ease forwards ${0.1+i*0.12}s;opacity:0">
    <div class="num" data-target="${s.num}">0</div>
    <div class="lbl">${s.lbl}</div>
  </div>`).join('');
  setTimeout(()=>{
    document.querySelectorAll('.stat-pill .num').forEach(el=>{
      animateCounter(el, parseInt(el.dataset.target));
    });
  }, 400);
}

function populateHomeOV(){
  const cats=Object.keys(CC).filter(c=>c!=='General');
  const catData=cats.map(cat=>{
    const sl=projects.filter(p=>p.category===cat&&p.link&&p.link.startsWith('http')).length;
    const ie=iepProjects.filter(p=>p.category===cat).length;
    return {cat,sl,ie,total:sl+ie};
  }).sort((a,b)=>b.total-a.total);

  const donutData=catData.map(d=>({label:d.cat,value:d.total,color:CC[d.cat]}));

  // Top Brands
  const bc={};
  projects.filter(p=>p.link&&p.link.startsWith('http')&&p.brand).forEach(p=>{bc[p.brand]=(bc[p.brand]||0)+1;});
  iepProjects.forEach(p=>{bc[p.brand]=(bc[p.brand]||0)+1;});
  const tb=Object.entries(bc).sort((a,b)=>b[1]-a[1]).slice(0,10);
  const mbr=tb[0]?tb[0][1]:1;

  // Build visual section
  const html=`
    <p style="font-size:12px;color:var(--text-muted);margin-bottom:16px;line-height:1.5">Totals include Social Listening reports and IEP experiments combined.</p>
    <!-- CATEGORY CARDS WITH SPARKLINES - 3 per row -->
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:32px" class="reveal">
      ${catData.map((d,i)=>`
        <div class="cat-ov-card" onclick="switchHome('${d.cat}')"
          style="border-top:3px solid ${CC[d.cat]};animation:fadeUp 0.5s ease forwards ${0.08*i}s;opacity:0"
          onmouseover="this.style.borderColor='${CC[d.cat]}';this.style.boxShadow='0 0 24px ${CC[d.cat]}20'"
          onmouseout="this.style.boxShadow=''">
          <div style="display:flex;justify-content:space-between;align-items:flex-start">
            <div>
              <div style="font-size:13px;font-weight:700;color:${CC[d.cat]};margin-bottom:6px">${d.cat}</div>
              <div style="font-size:30px;font-weight:800;color:var(--text-white);line-height:1">${d.total}</div>
            </div>
            <div style="text-align:right">
              <div style="font-size:10px;color:var(--accent-cyan);font-weight:600">${d.sl} SL</div>
              <div style="font-size:10px;color:var(--accent-iep);font-weight:600">${d.ie} IEP</div>
            </div>
          </div>
          ${drawSparkline(d.cat, CC[d.cat])}
          <div style="font-size:9px;color:var(--text-muted);margin-top:4px;display:flex;justify-content:space-between">
            <span>2021</span><span>2026</span>
          </div>
        </div>
      `).join('')}
    </div>

    <!-- 3-COLUMN: DONUT | BRANDS | TIMELINE -->
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:20px;margin-bottom:32px" class="reveal">
      <!-- DONUT CHART -->
      <div class="chart-card" style="animation:glowPulse 4s ease-in-out infinite">
        <h4 style="font-size:14px;font-weight:700;color:var(--text-white);margin-bottom:4px">Research Coverage by Category</h4>
        <p style="font-size:11px;color:var(--text-muted);margin-bottom:16px">Click a segment to explore insights</p>
        <div style="display:flex;flex-direction:column;align-items:center;gap:20px">
          <div style="flex-shrink:0">${drawDonut('donut',donutData,180)}</div>
          <div style="width:100%">
            ${catData.map((d,i)=>`
              <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;cursor:pointer;padding:4px 8px;border-radius:8px;transition:all 0.25s;border:1px solid transparent"
                onmouseover="this.style.background='rgba(255,255,255,0.04)';this.style.borderColor='rgba(255,255,255,0.08)'"
                onmouseout="this.style.background='transparent';this.style.borderColor='transparent'"
                onclick="switchHome('${d.cat}')">
                <div style="width:10px;height:10px;border-radius:3px;background:${CC[d.cat]};flex-shrink:0;box-shadow:0 0 6px ${CC[d.cat]}40"></div>
                <div style="flex:1;font-size:11px;color:var(--text-light);font-weight:500">${d.cat}</div>
                <div style="display:flex;gap:4px;font-size:10px;align-items:center">
                  <span style="background:rgba(42,184,180,0.1);color:var(--accent-cyan);padding:2px 6px;border-radius:10px;font-weight:600">${d.sl}</span>
                  <span style="background:rgba(107,138,242,0.1);color:var(--accent-iep);padding:2px 6px;border-radius:10px;font-weight:600">${d.ie}</span>
                </div>
              </div>
            `).join('')}
          </div>
        </div>
      </div>
      <!-- TOP BRANDS -->
      <div class="chart-card">
        <h4 style="font-size:14px;font-weight:700;color:var(--text-white);margin-bottom:4px">Top Brands by Volume</h4>
        <p style="font-size:11px;color:var(--text-muted);margin-bottom:16px">Hover for breakdown</p>
        ${tb.map(([b,n],i)=>{
          const pct=(n/mbr*100).toFixed(0);
          const slN=projects.filter(p=>p.brand===b&&p.link&&p.link.startsWith('http')).length;
          const iepN=iepProjects.filter(p=>p.brand===b).length;
          const catOfBrand=(projects.find(p=>p.brand===b)||{}).category||'General';
          const bColor=CC[catOfBrand]||'var(--accent-cyan)';
          return `<div class="bar-row" style="opacity:0;animation:slideIn 0.4s ease forwards ${0.06*i}s"
            onmouseover="showTip('<b>${b}</b><br>${slN} SL + ${iepN} IEP<br>Category: ${catOfBrand}')" onmouseout="hideTip()">
            <div class="bar-lbl" style="font-weight:${i<3?'600':'400'};color:${i<3?'var(--text-white)':'var(--text-muted)'}">${b}</div>
            <div class="bar-track">
              <div class="bar-fill" style="width:0%;background:linear-gradient(90deg,${bColor},${bColor}cc);animation:barGrow 0.8s ease forwards ${0.12+0.06*i}s;--target-width:${pct}%">
                <span class="bar-val">${n}</span>
              </div>
            </div>
          </div>`;
        }).join('')}
      </div>
      <!-- TIMELINE -->
      <div class="chart-card">
        <h4 style="font-size:14px;font-weight:700;color:var(--text-white);margin-bottom:4px">Project Timeline</h4>
        <p style="font-size:11px;color:var(--text-muted);margin-bottom:16px">Year-over-year &mdash; SL + IEP</p>
        <div id="timeline"></div>
      </div>
    </div>
  `;

  document.getElementById('homeOV').innerHTML=html;
  renderTimeline();
  setTimeout(initReveal,100);
}

function renderTimeline(){
  const years=[2021,2022,2023,2024,2025,2026];
  const slByYear={};
  projects.filter(p=>p.link&&p.link.startsWith('http')).forEach(p=>{slByYear[p.year]=(slByYear[p.year]||0)+1;});
  // Estimate IEP per year (most are 2023-2025)
  const iepByYear={2023:Math.round(iepProjects.length*0.2),2024:Math.round(iepProjects.length*0.45),2025:Math.round(iepProjects.length*0.3),2026:Math.round(iepProjects.length*0.05)};

  const maxY=Math.max(...years.map(y=>(slByYear[y]||0)+(iepByYear[y]||0)),1);
  const barH=120;

  let html=`<div style="display:flex;align-items:flex-end;gap:16px;padding:0 8px;height:${barH+50}px">`;
  years.forEach((y,i)=>{
    const sl=slByYear[y]||0;
    const iep=iepByYear[y]||0;
    const tot=sl+iep;
    const slH=(sl/maxY)*barH;
    const iepH=(iep/maxY)*barH;
    const delay=0.1+i*0.1;
    html+=`<div style="flex:1;text-align:center;opacity:0;animation:fadeUp 0.5s ease forwards ${delay}s">
      <div style="font-size:11px;color:var(--text-white);font-weight:700;margin-bottom:6px">${tot}</div>
      <div style="display:flex;flex-direction:column;align-items:center;position:relative"
        onmouseover="showTip('<b>${y}</b><br>${sl} SL reports<br>${iep} IEP experiments<br><b>${tot} total</b>')" onmouseout="hideTip()">
        ${iep>0?`<div style="width:80%;height:0px;background:var(--accent-iep);border-radius:4px 4px 0 0;transition:height 0.8s ease ${delay}s;animation:none" class="timeline-iep-bar" data-h="${iepH}"></div>`:''}
        <div style="width:80%;height:0px;background:var(--accent-cyan);border-radius:${iep>0?'0 0 4px 4px':'4px'};transition:height 0.8s ease ${delay}s;animation:none" class="timeline-sl-bar" data-h="${slH}"></div>
      </div>
      <div style="font-size:13px;color:var(--text-white);margin-top:8px;font-weight:700">${y}</div>
    </div>`;
  });
  html+=`</div>`;
  html+=`<div style="display:flex;gap:20px;justify-content:center;margin-top:16px;font-size:11px">
    <span style="display:flex;align-items:center;gap:6px"><span style="width:14px;height:8px;border-radius:2px;background:var(--accent-cyan)"></span><span style="color:var(--text-muted)">Social Listening</span></span>
    <span style="display:flex;align-items:center;gap:6px"><span style="width:14px;height:8px;border-radius:2px;background:var(--accent-iep)"></span><span style="color:var(--text-muted)">IEP</span></span>
  </div>`;

  document.getElementById('timeline').innerHTML=html;
  // Animate bars after a tick
  setTimeout(()=>{
    document.querySelectorAll('.timeline-sl-bar').forEach(el=>{el.style.height=el.dataset.h+'px';});
    document.querySelectorAll('.timeline-iep-bar').forEach(el=>{el.style.height=el.dataset.h+'px';});
  },100);
}

// ===== SHARED INSIGHT FUNCTIONS =====
function makeInsightTabs(containerId, switchFn){
  const cats=Object.keys(categoryInsights);
  document.getElementById(containerId).innerHTML=cats.map((c,i)=>`<button class="cat-tab ${i===0?'active':''}" onclick="${switchFn}('${c}')"><span class="cat-dot" style="background-color:${categoryInsights[c].color}"></span>${c}</button>`).join('');
}

function updateTabs(containerId, cat){
  document.querySelectorAll('#'+containerId+' .cat-tab').forEach(b=>{
    b.classList.remove('active');b.style.borderColor='';b.style.color='';
    if(b.textContent.trim().includes(cat)){b.classList.add('active');b.style.borderColor=categoryInsights[cat]?.color||'';b.style.color=categoryInsights[cat]?.color||'';}
  });
}

function LI(arr){return(arr||[]).map(x=>'<li style="margin-bottom:3px">'+x+'</li>').join('');}

function renderInsights(gridId, cat, showIEP){
  const ins=categoryInsights[cat].insights;
  const src=sourceMap[cat]||[];
  const cc=categoryInsights[cat].color;
  let h=ins.map((x,i)=>{
    const s=src.length>0?src[i%src.length]:null;
    const st=s?`<div class="insight-source"><strong>Source:</strong> <a href="${s.url}" target="_blank" style="color:var(--accent-cyan);text-decoration:none;transition:color 0.2s" onmouseover="this.style.textDecoration='underline'" onmouseout="this.style.textDecoration='none'">${s.label}</a><span class="src-badge src-sl">SL</span></div>`:'';
    return `<div class="insight-card" style="opacity:0;animation:fadeUp 0.4s ease forwards ${0.05*i}s">
      <div style="border-left:3px solid ${cc};padding-left:16px;border-radius:2px">
        <h4 style="color:${cc}">${x.title}</h4>
        <p>${x.text}</p>
        ${st}
      </div>
    </div>`;
  }).join('');

  // IEP product insights are shown only in Brand Deep Dive, not at category level
  document.getElementById(gridId).innerHTML=h;
}

function renderBrandDive(containerId, cat, showIEP){
  const bd=brandInsights[cat]||{};
  const bns=Object.keys(bd);
  // Also find IEP-only brands in this category
  const iepOnlyBrands=showIEP?[...new Set(iepProjects.filter(p=>p.category===cat).map(p=>p.brand))].filter(b=>!bd[b]&&iepBrandInsights[b]):[];
  if(!bns.length&&!iepOnlyBrands.length){document.getElementById(containerId).innerHTML='';return;}
  const cc=categoryInsights[cat].color;
  document.getElementById(containerId).innerHTML=`
    <div style="margin-top:28px" class="reveal visible">
      <div style="font-size:14px;color:var(--text-white);font-weight:700;margin-bottom:16px">${cat==="Shopper"?"Cross-Brand Insights":"Brand Deep Dive"}</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:16px">
        ${bns.map((b,bi)=>{
          const d=bd[b];const iep=showIEP?iepBrandInsights[b]:null;
          const iepSec=iep?`<div style="margin-top:12px;padding-top:12px;border-top:1px solid var(--border-dark)"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--accent-iep);font-weight:600;margin-bottom:6px">IEP Key Learnings</div><ul style="font-size:12px;color:var(--text-light);line-height:1.6;margin:0;padding-left:16px">${LI(iep.winning_claims)}</ul></div>`:'';
          return `<div style="background:var(--bg-card);border:1px solid var(--border-dark);border-radius:var(--radius);padding:20px;border-left:3px solid ${cc};transition:all 0.3s;opacity:0;animation:fadeUp 0.4s ease forwards ${0.08*bi}s"
            onmouseover="this.style.boxShadow='0 4px 24px rgba(0,0,0,0.3)';this.style.borderColor='rgba(255,255,255,0.12)'"
            onmouseout="this.style.boxShadow='';this.style.borderColor='var(--border-dark)'">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><span style="font-size:14px;font-weight:700;color:${cc}">${b}</span><span class="src-badge src-sl">SL</span>${iep?'<span class="src-badge src-iep">IEP</span>':''}</div>
            <div style="margin-bottom:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--accent-cyan);font-weight:600;margin-bottom:6px">Purchase Drivers</div><ul style="font-size:12px;color:var(--text-light);line-height:1.6;margin:0;padding-left:16px">${LI(d.drivers)}</ul></div>
            <div style="margin-bottom:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#E8734A;font-weight:600;margin-bottom:6px">Pain Points</div><ul style="font-size:12px;color:var(--text-light);line-height:1.6;margin:0;padding-left:16px">${LI(d.painPoints)}</ul></div>
            <div style="margin-bottom:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#ff6b6b;font-weight:600;margin-bottom:6px">Category Pitfalls</div><ul style="font-size:12px;color:var(--text-light);line-height:1.6;margin:0;padding-left:16px">${LI(d.pitfalls)}</ul></div>
            ${iepSec}
            <div style="background:rgba(155,107,242,0.08);border-radius:8px;padding:12px;margin-top:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#9B6BF2;font-weight:600;margin-bottom:4px">Strategic Opportunity</div><div style="font-size:12px;color:var(--text-light);line-height:1.5">${d.opportunity}</div></div>
          </div>`;
        }).join('')}
        ${iepOnlyBrands.map((b,bi)=>{
          const iep=iepBrandInsights[b];
          if(!iep)return '';
          return `<div style="background:var(--bg-card);border:1px solid var(--border-dark);border-radius:var(--radius);padding:20px;border-left:3px solid ${cc};transition:all 0.3s;opacity:0;animation:fadeUp 0.4s ease forwards ${0.08*(bns.length+bi)}s"
            onmouseover="this.style.boxShadow='0 4px 24px rgba(0,0,0,0.3)';this.style.borderColor='rgba(255,255,255,0.12)'"
            onmouseout="this.style.boxShadow='';this.style.borderColor='var(--border-dark)'">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:14px"><span style="font-size:14px;font-weight:700;color:${cc}">${b}</span><span class="src-badge src-iep">IEP</span></div>
            <div style="margin-bottom:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--accent-iep);font-weight:600;margin-bottom:6px">IEP Key Learnings</div><ul style="font-size:12px;color:var(--text-light);line-height:1.6;margin:0;padding-left:16px">${LI(iep.winning_claims)}</ul></div>
            <div style="background:rgba(155,107,242,0.08);border-radius:8px;padding:12px;margin-top:12px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#9B6BF2;font-weight:600;margin-bottom:4px">Strategic Opportunity</div><div style="font-size:12px;color:var(--text-light);line-height:1.5">${iep.strategic_rec}</div></div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
}

function switchHome(cat){updateTabs('homeTabs',cat);renderInsights('homeIG',cat,true);renderBrandDive('homeBD',cat,true);}
function switchSL(cat){updateTabs('slTabs',cat);renderInsights('slIG',cat,false);renderBrandDive('slBD',cat,false);}

function initHome(){
  populateStats();populateHomeOV();
  makeInsightTabs('homeTabs','switchHome');switchHome(Object.keys(categoryInsights)[0]);
}

// ===== SL PAGE =====
function initSL(){
  const cats=Object.keys(CC).filter(c=>c!=='General');
  document.getElementById('slOV').innerHTML=cats.map(cat=>{
    const n=projects.filter(p=>p.category===cat&&p.link&&p.link.startsWith('http')).length;
    return `<div class="cat-ov-card" onclick="document.getElementById('slCat').value='${cat}';filterSL();document.getElementById('slLib').scrollIntoView({behavior:'smooth'})" style="border-top:3px solid ${CC[cat]}">
      <div style="font-size:15px;font-weight:700;color:${CC[cat]};margin-bottom:8px">${cat}</div>
      <div style="font-size:28px;font-weight:800;color:var(--text-white);line-height:1">${n}</div>
      <div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;margin-top:4px">Projects</div>
    </div>`;
  }).join('');
  makeInsightTabs('slTabs','switchSL');switchSL(Object.keys(categoryInsights)[0]);
  const slWL=projects.filter(p=>p.link&&p.link.startsWith('http'));
  const yrs=[...new Set(slWL.map(p=>p.year))].sort((a,b)=>a-b);
  const cts=[...new Set(slWL.map(p=>p.category))].sort();
  const brs=[...new Set(slWL.map(p=>p.brand).filter(b=>b))].sort();
  document.getElementById('slYear').innerHTML+= yrs.map(y=>`<option value="${y}">${y}</option>`).join('');
  document.getElementById('slCat').innerHTML+= cts.map(c=>`<option value="${c}">${c}</option>`).join('');
  document.getElementById('slBrand').innerHTML+= brs.map(b=>`<option value="${b}">${b}</option>`).join('');
  filterSL();
}

function filterSL(){
  const s=document.getElementById('slSearch').value.toLowerCase();
  const y=document.getElementById('slYear').value;
  const c=document.getElementById('slCat').value;
  const b=document.getElementById('slBrand').value;
  slF=projects.filter(p=>{
    if(!p.link||!p.link.startsWith('http'))return false;
    const km=(p.keywords||[]).some(k=>k.toLowerCase().includes(s));
    const sm=s===''||p.theme.toLowerCase().includes(s)||p.brand.toLowerCase().includes(s)||p.category.toLowerCase().includes(s)||(p.summary||'').toLowerCase().includes(s)||(p.objective||'').toLowerCase().includes(s)||(p.tools||'').toLowerCase().includes(s)||km;
    return sm&&(y===''||p.year==y)&&(c===''||p.category===c)&&(b===''||p.brand===b);
  });
  document.getElementById('slCount').textContent=slF.length+' result'+(slF.length!==1?'s':'');
  renderSL();
}

function renderSL(){
  const el=document.getElementById('slCards');
  if(!slF.length){el.innerHTML='<p style="text-align:center;color:var(--text-muted);padding:40px">No projects match your filters.</p>';return;}
  if(slView==='grid'){
    el.innerHTML='<div class="projects-grid">'+slF.map(p=>{
      const cc=CC[p.category]||'#7C8A96';
      const tt=classifyTools(p.tools);
      const kw=(p.keywords||[]).slice(0,4);
      return `<div class="project-card" style="border-left:3px solid ${cc}">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:6px">
          <div style="flex:1;min-width:0">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px"><div class="brand-label">${p.brand||p.category}</div><span style="font-size:11px;color:#7a8ea0">${p.month||''} ${p.year}</span></div>
            <h3 class="card-title">${p.theme.replace(/\\n/g,' \u2014 ')}</h3>
          </div>
          <span class="badge" style="background:${cc};flex-shrink:0">${p.category}</span>
        </div>
        ${p.summary?`<div class="card-summary">${p.summary}</div>`:''}
        ${kw.length?`<div class="card-keywords">${kw.map(k=>`<span class="kw-tag">${k}</span>`).join('')}</div>`:''}
        ${p.requestor?`<div class="card-requestor">Requested by: ${p.requestor}</div>`:''}
        <div class="card-footer">
          <div class="tools-list">${tt.map(t=>`<span class="tool-tag">${t}</span>`).join('')}</div>
          <a href="${p.link}" target="_blank" class="link-btn">Open \u2192</a>
        </div>
      </div>`;
    }).join('')+'</div>';
  } else {
    el.innerHTML='<div class="projects-list">'+slF.map(p=>`<div class="project-card">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div style="flex:1;min-width:0">
          <div style="margin-bottom:4px"><span class="brand-label">${p.brand||p.category}</span><span style="font-size:11px;color:var(--text-muted);margin-left:12px">${p.month} ${p.year}</span></div>
          <h3 class="card-title">${p.theme.replace(/\\n/g,' \u2014 ')}</h3>
          ${p.summary?`<div class="card-summary">${p.summary}</div>`:''}
        </div>
        <a href="${p.link}" target="_blank" class="link-btn" style="white-space:nowrap;margin-left:16px">Open \u2192</a>
      </div>
    </div>`).join('')+'</div>';
  }
}

function setSLV(v){slView=v;document.getElementById('slGBtn').classList.toggle('active',v==='grid');document.getElementById('slLBtn').classList.toggle('active',v==='list');renderSL();}
function clearSL(){document.getElementById('slSearch').value='';document.getElementById('slYear').value='';document.getElementById('slCat').value='';document.getElementById('slBrand').value='';filterSL();}


function switchIEPBrand(b){
  document.querySelectorAll('.iep-bi-tab').forEach(t=>{
    t.classList.remove('active');t.style.borderColor='';t.style.color='';
    if(t.dataset.brand===b){t.classList.add('active');t.style.borderColor=t.dataset.color;t.style.color=t.dataset.color;}
  });
  const d=iepBrandInsights[b];if(!d)return;
  const brandCatMap2={};iepProjects.forEach(p=>{if(!brandCatMap2[p.brand])brandCatMap2[p.brand]=p.category;});
  const brandCat=brandCatMap2[b]||'General';
  const brandColor=CC[brandCat]||'#6B8AF2';
  document.getElementById('iepBIContent').innerHTML=`<div style="background:var(--bg-card);border:1px solid var(--border-dark);border-radius:var(--radius);padding:24px;border-left:4px solid ${brandColor};animation:fadeUp 0.3s ease forwards"
    onmouseover="this.style.boxShadow='0 4px 24px ${brandColor}15';this.style.borderColor='${brandColor}'"
    onmouseout="this.style.boxShadow='';this.style.borderColor='var(--border-dark)'">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:16px">
      <div style="font-size:16px;font-weight:700;color:${brandColor}">${b}</div>
      <span style="background:${brandColor}18;color:${brandColor};padding:3px 10px;border-radius:12px;font-size:10px;font-weight:600;letter-spacing:0.5px">${brandCat}</span>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px">
      <div style="background:rgba(255,255,255,0.02);border-radius:10px;padding:16px;border:1px solid rgba(255,255,255,0.04)">
        <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:${brandColor};font-weight:600;margin-bottom:8px">Key Learnings</div>
        <ul style="font-size:12px;color:var(--text-light);line-height:1.7;margin:0;padding-left:16px">${LI(d.winning_claims)}</ul>
      </div>
      <div style="background:rgba(255,255,255,0.02);border-radius:10px;padding:16px;border:1px solid rgba(255,255,255,0.04)">
        <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--text-light);font-weight:600;margin-bottom:8px">Consumer Behavior</div>
        <ul style="font-size:12px;color:var(--text-light);line-height:1.7;margin:0;padding-left:16px">${LI(d.consumer_behavior)}</ul>
      </div>
    </div>
    <div style="background:${brandColor}0a;border:1px solid ${brandColor}18;border-radius:10px;padding:14px;margin-top:14px">
      <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:${brandColor};font-weight:600;margin-bottom:4px">Strategic Recommendation</div>
      <div style="font-size:12px;color:var(--text-light);line-height:1.6">${d.strategic_rec}</div>
    </div>
  </div>`;
}

// ===== IEP PAGE =====
function initIEP(){
  const cats=Object.keys(CC).filter(c=>c!=='General'&&iepProjects.some(p=>p.category===c));
  document.getElementById('iepOV').innerHTML=cats.map(cat=>{
    const n=iepProjects.filter(p=>p.category===cat).length;
    const rds=iepProjects.filter(p=>p.category===cat).reduce((s,p)=>s+p.rounds,0);
    return `<div class="cat-ov-card" onclick="filterIEPCat('${cat}')" style="border-top:3px solid ${CC[cat]}">
      <div style="font-size:15px;font-weight:700;color:${CC[cat]};margin-bottom:12px">${cat}</div>
      <div style="display:flex;gap:20px">
        <div style="text-align:center"><div style="font-size:22px;font-weight:800;color:var(--text-white)">${n}</div><div style="font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;margin-top:2px">Experiments</div></div>
        <div style="text-align:center"><div style="font-size:22px;font-weight:800;color:var(--text-white)">${rds}</div><div style="font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:.5px;margin-top:2px">Rounds</div></div>
      </div>
    </div>`;
  }).join('');

  document.getElementById('iepPat').innerHTML=iepPatterns.map((p,i)=>`<div class="pat-card"><span class="pat-num">${i+1}</span>${p}</div>`).join('');

  // Build brand-to-category map for coloring
  const brandCatMap={};
  iepProjects.forEach(p=>{if(!brandCatMap[p.brand])brandCatMap[p.brand]=p.category;});

  // IEP Brand Insights - tabbed by brand (like SL style)
  const iepBrands=Object.keys(iepBrandInsights).sort();
  const halfIdx=Math.ceil(iepBrands.length/2);
  let biTabs='<div style="margin-top:28px"><div style="font-size:14px;color:var(--text-white);font-weight:700;margin-bottom:16px">Brand Insights</div>';
  biTabs+='<div id="iepBITabs">';
  // Line 1
  biTabs+='<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:8px">';
  iepBrands.slice(0,halfIdx).forEach((b,i)=>{
    const bCat=brandCatMap[b]||'General';
    const bCol=CC[bCat]||'#6B8AF2';
    biTabs+=`<button class="cat-tab iep-bi-tab${i===0?' active':''}" data-brand="${b}" data-color="${bCol}" onclick="switchIEPBrand('${b.replace(/'/g,"\\'")}')" style="${i===0?'border-color:'+bCol+';color:'+bCol:''}"><span class="cat-dot" style="background-color:${bCol}"></span>${b}</button>`;
  });
  biTabs+='</div>';
  // Line 2
  biTabs+='<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px">';
  iepBrands.slice(halfIdx).forEach((b,i)=>{
    const idx=halfIdx+i;
    const bCat=brandCatMap[b]||'General';
    const bCol=CC[bCat]||'#6B8AF2';
    biTabs+=`<button class="cat-tab iep-bi-tab" data-brand="${b}" data-color="${bCol}" onclick="switchIEPBrand('${b.replace(/'/g,"\\'")}')" style=""><span class="cat-dot" style="background-color:${bCol}"></span>${b}</button>`;
  });
  biTabs+='</div>';
  biTabs+='</div><div id="iepBIContent"></div></div>';
  document.getElementById('iepBI').innerHTML=biTabs;
  if(iepBrands.length)switchIEPBrand(iepBrands[0]);

  const allCats=[...new Set(iepProjects.map(p=>p.category))].sort();
  const allBr=[...new Set(iepProjects.map(p=>p.brand))].sort();
  // Line 1: All + Categories
  let fh='<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px">';
  fh+='<button class="iep-fbtn active" onclick="filterIEPBr(\'\')">All</button>';
  allCats.forEach(c=>{
    const catColor=CC[c]||'#6B8AF2';
    fh+=`<button class="iep-fbtn iep-cat-btn" data-cat="${c}" data-color="${catColor}" onclick="filterIEPCat('${c}')">${c}</button>`;
  });
  fh+='</div>';
  // Line 2: Brands
  fh+='<div style="display:flex;gap:8px;flex-wrap:wrap">';
  allBr.forEach(b=>{
    // Find brand's category for coloring
    const bCat=(iepProjects.find(p=>p.brand===b)||{}).category||'General';
    const bColor=CC[bCat]||'#6B8AF2';
    fh+=`<button class="iep-fbtn iep-brand-btn" data-brand="${b}" data-color="${bColor}" data-cat="${bCat}" onclick="filterIEPBr('${b}')" style="font-size:11px">${b}</button>`;
  });
  fh+='</div>';
  document.getElementById('iepFR').innerHTML=fh;
  renderIEPLib();
}

function resetIEPBtnStyles(){
  document.querySelectorAll('.iep-fbtn').forEach(x=>{
    x.classList.remove('active');
    x.style.background='';x.style.borderColor='';x.style.color='';
  });
}
function filterIEPBr(b){
  iepFB=b;iepSearch='';document.getElementById('iepSearchInput').value='';
  resetIEPBtnStyles();
  if(!b){
    document.querySelector('.iep-fbtn').classList.add('active');
  } else {
    const btn=document.querySelector(`.iep-brand-btn[data-brand="${b}"]`);
    if(btn){
      const col=btn.dataset.color;
      btn.classList.add('active');
      btn.style.background=col+'20';btn.style.borderColor=col+'50';btn.style.color=col;
    }
  }
  renderIEPLib();
}
function filterIEPCat(c){
  iepFB='cat:'+c;iepSearch='';document.getElementById('iepSearchInput').value='';
  resetIEPBtnStyles();
  const btn=document.querySelector(`.iep-cat-btn[data-cat="${c}"]`);
  if(btn){
    const col=btn.dataset.color;
    btn.classList.add('active');
    btn.style.background=col+'20';btn.style.borderColor=col+'50';btn.style.color=col;
  }
  renderIEPLib();
}
function filterIEPSearch(){iepSearch=document.getElementById('iepSearchInput').value.toLowerCase();renderIEPLib();}

function renderIEPLib(){
  let f=iepProjects;
  if(iepFB){
    if(iepFB.startsWith('cat:'))f=iepProjects.filter(p=>p.category===iepFB.replace('cat:',''));
    else f=iepProjects.filter(p=>p.brand===iepFB);
  }
  if(iepSearch){
    f=f.filter(p=>p.brand.toLowerCase().includes(iepSearch)||p.project_name.toLowerCase().includes(iepSearch)||p.category.toLowerCase().includes(iepSearch)||(p.summary||'').toLowerCase().includes(iepSearch)||(p.keywords||[]).some(k=>k.toLowerCase().includes(iepSearch)));
  }
  document.getElementById('iepCount').textContent=f.length;
  document.getElementById('iepLG').innerHTML=f.map(p=>{
    const cc=CC[p.category]||'#7C8A96';
    const kw=(p.keywords||[]).slice(0,4);
    return `<div class="project-card" style="border-left:3px solid ${cc}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:6px">
        <div style="flex:1;min-width:0">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
            <div class="brand-label" style="background:${cc}">${p.brand}</div>
          </div>
          <h3 class="card-title">${p.experiment_id} \u2014 ${p.project_name}</h3>
        </div>
        <span class="badge" style="background:${cc};flex-shrink:0">${p.category}</span>
      </div>
      ${p.summary?`<div class="card-summary">${p.summary}</div>`:''}
      ${kw.length?`<div class="card-keywords">${kw.map(k=>`<span class="kw-tag">${k}</span>`).join('')}</div>`:''}
      <div style="display:flex;gap:12px;align-items:center;font-size:11px;color:#7a8ea0;margin-top:8px;flex-wrap:wrap">
        <span>${p.rounds===0?'<span style="color:#ff6b6b;font-weight:600">Cancelled</span>':p.rounds+' round'+(p.rounds>1?'s':'')}</span>
        ${(p.rounds>0&&typeof learningJourneyMap!=='undefined'&&learningJourneyMap[p.brand+'|'+p.experiment_id])?(()=>{const ljs=learningJourneyMap[p.brand+'|'+p.experiment_id];return ljs.map((lj,li)=>{const ljUrl=typeof lj==='object'?lj.url:lj;const ljFile=typeof lj==='object'?lj.file:lj;return '<a href="'+ljUrl+'" target="_blank" style="background:rgba(107,138,242,0.1);color:#6B8AF2;padding:2px 8px;border-radius:8px;font-size:10px;font-weight:600;cursor:pointer;text-decoration:none;transition:all 0.2s;border:1px solid rgba(107,138,242,0.15)" onmouseover="this.style.background=\'rgba(107,138,242,0.2)\';this.style.borderColor=\'rgba(107,138,242,0.4)\'" onmouseout="this.style.background=\'rgba(107,138,242,0.1)\';this.style.borderColor=\'rgba(107,138,242,0.15)\'" title="'+ljFile+'">'+(ljs.length>1?'Learning Journey '+(li+1):'Learning Journey')+'</a>';}).join('');})():''}
      </div>
    </div>`;
  }).join('')||'<p style="text-align:center;color:var(--text-muted);padding:40px">No experiments match this filter.</p>';
}

